import json
from jsonschema import validate, ValidationError

# Örnek JSON veri
data = {
    "name": "Alice",
    "age": 30,
    "city": "New York",
    "isStudent": False,
    "courses": ["Math", "Physics"]
}

# Örnek JSON şema
schema = {
    "type": "object",
    "properties": {
        "name": {"type": "string"},
        "age": {"type": "integer", "minimum": 0},
        "city": {"type": "string"},
        "isStudent": {"type": "boolean"},
        "courses": {
            "type": "array",
            "items": {"type": "string"}
        }
    },
    "required": ["name", "age", "city"]
}

try:
    validate(instance=data, schema=schema)
    print("JSON verisi şemaya uygun.")
except ValidationError as e:
    print(f"JSON verisi şemaya uygun değil: {e.message}")
except Exception as e:
    print(f"Bir hata oluştu: {e}")

# Şemaya uymayan başka bir örnek
invalid_data = {
    "name": "Bob",
    "age": -5,  # Hatalı: age minimum 0
    "city": 123  # Hatalı: city string olmalı
}

print("\n--- İkinci doğrulama ---")
try:
    validate(instance=invalid_data, schema=schema)
    print("JSON verisi şemaya uygun.")
except ValidationError as e:
    print(f"JSON verisi şemaya uygun değil: {e.message}")
except Exception as e:
    print(f"Bir hata oluştu: {e}")

# Gerekli alan eksikliği
missing_required_data = {
    "name": "Charlie",
    "age": 25
    # city alanı eksik
}

print("\n--- Üçüncü doğrulama (Gerekli alan eksikliği) ---")
try:
    validate(instance=missing_required_data, schema=schema)
    print("JSON verisi şemaya uygun.")
except ValidationError as e:
    print(f"JSON verisi şemaya uygun değil: {e.message}")
except Exception as e:
    print(f"Bir hata oluştu: {e}")
